# Randomization Design Lab
# Educational Shiny app comparing complete, stratified, covariate-adaptive,
# and response-adaptive randomization in one shared trial setting.

library(shiny)
library(ggplot2)
library(dplyr)
library(tidyr)
library(DT)

methods_available <- c(
  "Complete",
  "Stratified complete",
  "Stratified permuted blocks",
  "Covariate-adaptive",
  "Response-adaptive"
)

method_info <- tibble::tribble(
  ~method, ~uses, ~main_gain, ~main_cost,
  "Complete", "Fixed allocation probabilities only", "Simple and highly unpredictable", "Can produce finite-sample balance differences",
  "Stratified complete", "Baseline stratum membership", "Makes subgroup-specific behavior visible", "Local balance is still not guaranteed",
  "Stratified permuted blocks", "Baseline stratum membership and previous assignments within each stratum", "Improves local treatment balance", "Can be more predictable and sparse strata can be awkward",
  "Covariate-adaptive", "Accrued baseline covariate distribution", "Balances several covariates without full cross-classification", "Needs real-time covariates, software, and analysis alignment",
  "Response-adaptive", "Accrued outcomes", "Can shift allocation toward the better-looking treatment", "Sensitive to delayed/noisy outcomes and can reduce precision"
)

parse_method_selection <- function(x) {
  selected <- methods_available[methods_available %in% x]
  if (length(selected) == 0) {
    selected <- c("Complete", "Stratified permuted blocks", "Covariate-adaptive")
  }
  selected
}

parse_covariates <- function(x) {
  covs <- c("center", "age_group", "stage", "sex")
  out <- covs[covs %in% x]
  if (length(out) == 0) out <- c("center", "age_group", "stage")
  out
}

generate_enrollment <- function(N, n_centers, seed,
                                older_prob = 0.45,
                                advanced_prob = 0.35,
                                male_prob = 0.50) {
  set.seed(seed)
  center_weights <- exp(seq(0.8, -0.8, length.out = n_centers))
  center_weights <- center_weights / sum(center_weights)
  center <- sample(paste0("Center ", seq_len(n_centers)), N, replace = TRUE, prob = center_weights)
  center_index <- as.integer(factor(center, levels = paste0("Center ", seq_len(n_centers))))
  center_shift <- scales::rescale(center_index, to = c(-0.12, 0.12))

  age_group <- ifelse(
    rbinom(N, 1, pmin(pmax(older_prob + center_shift, 0.05), 0.95)) == 1,
    "Older", "Younger"
  )
  stage <- ifelse(
    rbinom(N, 1, pmin(pmax(advanced_prob + 0.7 * center_shift, 0.05), 0.95)) == 1,
    "Advanced", "Early"
  )
  sex <- ifelse(rbinom(N, 1, male_prob) == 1, "Male", "Female")

  tibble(
    id = seq_len(N),
    center = factor(center, levels = paste0("Center ", seq_len(n_centers))),
    age_group = factor(age_group, levels = c("Younger", "Older")),
    stage = factor(stage, levels = c("Early", "Advanced")),
    sex = factor(sex, levels = c("Female", "Male"))
  )
}

stratum_key <- function(dat, vars) {
  if (length(vars) == 0) return(rep("All", nrow(dat)))
  apply(dat[, vars, drop = FALSE], 1, paste, collapse = " / ")
}

assign_complete <- function(dat, p_A = 0.5) {
  N <- nrow(dat)
  trt <- ifelse(rbinom(N, 1, p_A) == 1, "A", "B")
  tibble(
    treatment = trt,
    prob_A = rep(p_A, N),
    score_A = NA_real_,
    score_B = NA_real_,
    observed_A = NA_integer_,
    observed_B = NA_integer_
  )
}

assign_stratified_complete <- function(dat, strata_vars, p_A = 0.5) {
  N <- nrow(dat)
  keys <- stratum_key(dat, strata_vars)
  trt <- character(N)
  prob_A <- numeric(N)
  for (key in unique(keys)) {
    idx <- which(keys == key)
    trt[idx] <- ifelse(rbinom(length(idx), 1, p_A) == 1, "A", "B")
    prob_A[idx] <- p_A
  }
  tibble(
    treatment = trt,
    prob_A = prob_A,
    score_A = NA_real_,
    score_B = NA_real_,
    observed_A = NA_integer_,
    observed_B = NA_integer_
  )
}

make_block <- function(block_size) {
  sample(rep(c("A", "B"), each = block_size / 2))
}

assign_stratified_blocks <- function(dat, strata_vars, block_size = 4) {
  N <- nrow(dat)
  keys <- stratum_key(dat, strata_vars)
  trt <- character(N)
  prob_A <- numeric(N)

  for (key in unique(keys)) {
    idx <- which(keys == key)
    block <- character(0)
    remaining <- c(A = 0, B = 0)

    for (j in idx) {
      if (length(block) == 0) {
        block <- make_block(block_size)
        remaining <- table(factor(block, levels = c("A", "B")))
      }
      total_remaining <- sum(remaining)
      prob_A[j] <- as.numeric(remaining["A"]) / total_remaining
      trt[j] <- block[1]
      remaining[trt[j]] <- remaining[trt[j]] - 1
      block <- block[-1]
    }
  }

  tibble(
    treatment = trt,
    prob_A = prob_A,
    score_A = NA_real_,
    score_B = NA_real_,
    observed_A = NA_integer_,
    observed_B = NA_integer_
  )
}

imbalance_score <- function(history, candidate, covs, overall_weight = 0.5) {
  if (nrow(history) == 0) return(0)
  tmp <- bind_rows(history, candidate)
  score <- overall_weight * abs(sum(tmp$treatment == "A") - sum(tmp$treatment == "B"))

  for (v in covs) {
    current_level <- as.character(candidate[[v]][1])
    sub <- tmp %>% filter(.data[[v]] == current_level)
    score <- score + abs(sum(sub$treatment == "A") - sum(sub$treatment == "B"))
  }
  score
}

assign_minimization <- function(dat, covs, favor_prob = 0.8) {
  N <- nrow(dat)
  trt <- character(N)
  prob_A <- numeric(N)
  score_A <- numeric(N)
  score_B <- numeric(N)
  history <- dat[0, ] %>% mutate(treatment = character())

  for (i in seq_len(N)) {
    row <- dat[i, , drop = FALSE]
    cand_A <- row %>% mutate(treatment = "A")
    cand_B <- row %>% mutate(treatment = "B")
    score_A[i] <- imbalance_score(history, cand_A, covs)
    score_B[i] <- imbalance_score(history, cand_B, covs)

    if (score_A[i] < score_B[i]) {
      prob_A[i] <- favor_prob
    } else if (score_B[i] < score_A[i]) {
      prob_A[i] <- 1 - favor_prob
    } else {
      prob_A[i] <- 0.5
    }

    trt[i] <- ifelse(runif(1) < prob_A[i], "A", "B")
    history <- bind_rows(history, row %>% mutate(treatment = trt[i]))
  }

  tibble(
    treatment = trt,
    prob_A = prob_A,
    score_A = score_A,
    score_B = score_B,
    observed_A = NA_integer_,
    observed_B = NA_integer_
  )
}

response_prob <- function(success_A, total_A, success_B, total_B, strength) {
  mean_A <- (success_A + 1) / (total_A + 2)
  mean_B <- (success_B + 1) / (total_B + 2)
  raw <- plogis(strength * (mean_A - mean_B))
  pmin(pmax(raw, 0.10), 0.90)
}

outcome_probabilities <- function(ids, N, params) {
  progress <- if (N <= 1) rep(0, length(ids)) else (ids - 1) / (N - 1)
  tibble(
    true_prob_A_i = rep(params$true_p_A, length(ids)),
    true_prob_B_i = pmin(pmax(params$true_p_B + params$time_trend_B * progress, 0.01), 0.99)
  )
}

draw_assigned_outcome <- function(id, treatment, N, params) {
  probs <- outcome_probabilities(id, N, params)
  prob <- if (treatment == "A") probs$true_prob_A_i else probs$true_prob_B_i
  rbinom(1, 1, prob)
}

assign_response_adaptive <- function(dat, true_p_A, true_p_B,
                                     burn_in = 20, delay = 0,
                                     strength = 4, time_trend_B = 0) {
  N <- nrow(dat)
  trt <- character(N)
  outcome <- rep(NA_integer_, N)
  prob_A <- numeric(N)
  observed_A <- integer(N)
  observed_B <- integer(N)

  for (i in seq_len(N)) {
    available <- which(seq_len(N) < i & seq_len(N) + delay < i & !is.na(outcome))
    success_A <- sum(outcome[available] == 1 & trt[available] == "A")
    total_A <- sum(trt[available] == "A")
    success_B <- sum(outcome[available] == 1 & trt[available] == "B")
    total_B <- sum(trt[available] == "B")
    observed_A[i] <- total_A
    observed_B[i] <- total_B

    if (i <= burn_in) {
      prob_A[i] <- 0.5
    } else {
      prob_A[i] <- response_prob(success_A, total_A, success_B, total_B, strength)
    }

    trt[i] <- ifelse(runif(1) < prob_A[i], "A", "B")
    outcome[i] <- draw_assigned_outcome(
      dat$id[i],
      trt[i],
      N,
      list(true_p_A = true_p_A, true_p_B = true_p_B, time_trend_B = time_trend_B)
    )
  }

  tibble(
    treatment = trt,
    prob_A = prob_A,
    score_A = NA_real_,
    score_B = NA_real_,
    observed_A = observed_A,
    observed_B = observed_B,
    outcome = outcome
  )
}

assign_by_method <- function(method, dat, params) {
  if (method == "Complete") {
    return(assign_complete(dat, params$p_A))
  }
  if (method == "Stratified complete") {
    return(assign_stratified_complete(dat, params$strata_vars, params$p_A))
  }
  if (method == "Stratified permuted blocks") {
    return(assign_stratified_blocks(dat, params$strata_vars, params$block_size))
  }
  if (method == "Covariate-adaptive") {
    return(assign_minimization(dat, params$adaptive_covs, params$favor_prob))
  }
  if (method == "Response-adaptive") {
    return(assign_response_adaptive(
      dat,
      true_p_A = params$true_p_A,
      true_p_B = params$true_p_B,
      burn_in = params$burn_in,
      delay = params$outcome_delay,
      strength = params$adapt_strength,
      time_trend_B = params$time_trend_B
    ))
  }
  stop("Unknown method")
}

simulate_one_trial <- function(enrollment, methods, params, seed) {
  out <- vector("list", length(methods))
  names(out) <- methods

  for (m in methods) {
    set.seed(seed + match(m, methods_available) * 1009)
    alloc <- assign_by_method(m, enrollment, params)
    dat <- bind_cols(enrollment, alloc) %>%
      mutate(
        method = m,
        treatment = factor(treatment, levels = c("A", "B")),
        cum_A = cumsum(treatment == "A"),
        cum_B = cumsum(treatment == "B"),
        imbalance = cum_A - cum_B,
        cum_prop_A = cum_A / id,
        guess_prob = pmax(prob_A, 1 - prob_A)
      )
    if (!"outcome" %in% names(dat)) {
      dat$outcome <- vapply(
        seq_len(nrow(dat)),
        function(i) draw_assigned_outcome(dat$id[i], as.character(dat$treatment[i]), nrow(dat), params),
        integer(1)
      )
    }
    probs <- outcome_probabilities(dat$id, nrow(dat), params)
    dat$true_prob_A_i <- probs$true_prob_A_i
    dat$true_prob_B_i <- probs$true_prob_B_i
    out[[m]] <- dat
  }

  bind_rows(out) %>%
    mutate(method = factor(method, levels = methods_available))
}

categorical_smd <- function(dat, covariate) {
  levels_v <- levels(dat[[covariate]])
  if (is.null(levels_v)) levels_v <- unique(as.character(dat[[covariate]]))
  vals <- numeric(length(levels_v))

  for (i in seq_along(levels_v)) {
    lvl <- levels_v[i]
    pA <- mean(dat[[covariate]][dat$treatment == "A"] == lvl)
    pB <- mean(dat[[covariate]][dat$treatment == "B"] == lvl)
    pA <- ifelse(is.nan(pA), 0, pA)
    pB <- ifelse(is.nan(pB), 0, pB)
    pooled <- (pA + pB) / 2
    denom <- sqrt(pooled * (1 - pooled))
    vals[i] <- ifelse(denom > 0, abs(pA - pB) / denom, 0)
  }

  max(vals, na.rm = TRUE)
}

covariate_balance_long <- function(dat) {
  covs <- c("center", "age_group", "stage", "sex")
  dat %>%
    group_by(method) %>%
    group_modify(~{
      tibble(
        covariate = covs,
        max_abs_smd = vapply(covs, function(v) categorical_smd(.x, v), numeric(1))
      )
    }) %>%
    ungroup()
}

adjusted_effect <- function(x) {
  x <- x %>%
    mutate(
      trt_A = as.integer(treatment == "A"),
      enrollment_scaled = if (max(id) == min(id)) 0 else (id - min(id)) / (max(id) - min(id))
    )
  fit <- stats::lm(outcome ~ trt_A + center + age_group + stage + sex + enrollment_scaled, data = x)
  coefs <- summary(fit)$coefficients
  if (!"trt_A" %in% rownames(coefs)) {
    return(tibble(adjusted_estimate = NA_real_, adjusted_se = NA_real_))
  }
  tibble(
    adjusted_estimate = unname(coefs["trt_A", "Estimate"]),
    adjusted_se = unname(coefs["trt_A", "Std. Error"])
  )
}

trial_metrics <- function(dat, true_p_A = NULL, true_p_B = NULL, time_trend_B = 0) {
  covs <- c("center", "age_group", "stage", "sex")
  avg_true_p_B <- if (!is.null(true_p_B)) true_p_B + time_trend_B / 2 else NA_real_
  true_effect <- if (!is.null(true_p_A) && !is.null(true_p_B)) true_p_A - avg_true_p_B else NA_real_
  dat %>%
    group_by(method) %>%
    group_modify(~{
      x <- .x
      final_A <- sum(x$treatment == "A")
      final_B <- sum(x$treatment == "B")
      observed_A <- x$outcome[x$treatment == "A"]
      observed_B <- x$outcome[x$treatment == "B"]
      estimate_rd <- mean(observed_A) - mean(observed_B)
      se_rd <- sqrt(
        stats::var(observed_A) / length(observed_A) +
          stats::var(observed_B) / length(observed_B)
      )
      ci_low <- estimate_rd - 1.96 * se_rd
      ci_high <- estimate_rd + 1.96 * se_rd
      unadjusted_coverage <- as.numeric(ci_low <= true_effect && ci_high >= true_effect)
      unadjusted_reject_null <- as.numeric(!is.na(se_rd) && se_rd > 0 && abs(estimate_rd / se_rd) > 1.96)
      adj <- adjusted_effect(x)
      adjusted_ci_low <- adj$adjusted_estimate - 1.96 * adj$adjusted_se
      adjusted_ci_high <- adj$adjusted_estimate + 1.96 * adj$adjusted_se
      adjusted_coverage <- as.numeric(adjusted_ci_low <= true_effect && adjusted_ci_high >= true_effect)
      adjusted_reject_null <- as.numeric(!is.na(adj$adjusted_se) && adj$adjusted_se > 0 && abs(adj$adjusted_estimate / adj$adjusted_se) > 1.96)
      time_balance <- mean(x$id[x$treatment == "A"]) - mean(x$id[x$treatment == "B"])
      center_deviation <- x %>%
        group_by(center) %>%
        summarise(prop_A = mean(treatment == "A"), .groups = "drop") %>%
        summarise(max_dev = max(abs(prop_A - 0.5), na.rm = TRUE)) %>%
        pull(max_dev)

      tibble(
        final_imbalance = abs(final_A - final_B),
        max_temporal_imbalance = max(abs(x$imbalance)),
        max_center_allocation_deviation = center_deviation,
        max_covariate_smd = max(vapply(covs, function(v) categorical_smd(x, v), numeric(1))),
        mean_guess_probability = mean(x$guess_prob, na.rm = TRUE),
        proportion_A = mean(x$treatment == "A"),
        mean_enrollment_order_difference = time_balance,
        risk_difference_estimate = estimate_rd,
        risk_difference_bias = estimate_rd - true_effect,
        risk_difference_se = se_rd,
        risk_difference_coverage = unadjusted_coverage,
        risk_difference_reject_null = unadjusted_reject_null,
        adjusted_risk_difference_estimate = adj$adjusted_estimate,
        adjusted_risk_difference_bias = adj$adjusted_estimate - true_effect,
        adjusted_risk_difference_se = adj$adjusted_se,
        adjusted_risk_difference_coverage = adjusted_coverage,
        adjusted_risk_difference_reject_null = adjusted_reject_null
      )
    }) %>%
    ungroup()
}

run_monte_carlo <- function(N, n_centers, methods, params, seed, M) {
  metrics <- vector("list", M)

  for (i in seq_len(M)) {
    enrollment <- generate_enrollment(N, n_centers, seed + i)
    sim <- simulate_one_trial(enrollment, methods, params, seed + 10000 + i)
    metrics[[i]] <- trial_metrics(sim, params$true_p_A, params$true_p_B, params$time_trend_B) %>% mutate(rep = i)
  }

  bind_rows(metrics)
}

format_metric_summary <- function(mc) {
  wide <- mc %>%
    group_by(method) %>%
    summarise(
      bias_unadjusted = mean(risk_difference_bias),
      bias_adjusted = mean(adjusted_risk_difference_bias, na.rm = TRUE),
      empirical_se_unadjusted = stats::sd(risk_difference_estimate),
      empirical_se_adjusted = stats::sd(adjusted_risk_difference_estimate, na.rm = TRUE),
      coverage_unadjusted = mean(risk_difference_coverage, na.rm = TRUE),
      coverage_adjusted = mean(adjusted_risk_difference_coverage, na.rm = TRUE),
      rejection_unadjusted = mean(risk_difference_reject_null, na.rm = TRUE),
      rejection_adjusted = mean(adjusted_risk_difference_reject_null, na.rm = TRUE),
      .groups = "drop"
    )

  bind_rows(
    wide %>% transmute(method, Metric = "Bias", Unadjusted = bias_unadjusted, Adjusted = bias_adjusted),
    wide %>% transmute(method, Metric = "Empirical SE", Unadjusted = empirical_se_unadjusted, Adjusted = empirical_se_adjusted),
    wide %>% transmute(method, Metric = "95% CI coverage", Unadjusted = coverage_unadjusted, Adjusted = coverage_adjusted),
    wide %>% transmute(method, Metric = "Rejection rate", Unadjusted = rejection_unadjusted, Adjusted = rejection_adjusted)
  ) %>%
    arrange(method, factor(Metric, levels = c("Bias", "Empirical SE", "95% CI coverage", "Rejection rate")))
}

format_single_trial_summary <- function(metrics) {
  bind_rows(
    metrics %>% transmute(method, Metric = "Risk-difference estimate", Unadjusted = risk_difference_estimate, Adjusted = adjusted_risk_difference_estimate),
    metrics %>% transmute(method, Metric = "Bias", Unadjusted = risk_difference_bias, Adjusted = adjusted_risk_difference_bias),
    metrics %>% transmute(method, Metric = "Model-based SE", Unadjusted = risk_difference_se, Adjusted = adjusted_risk_difference_se),
    metrics %>% transmute(method, Metric = "95% CI covers true value", Unadjusted = risk_difference_coverage, Adjusted = adjusted_risk_difference_coverage),
    metrics %>% transmute(method, Metric = "Rejects null", Unadjusted = risk_difference_reject_null, Adjusted = adjusted_risk_difference_reject_null)
  ) %>%
    arrange(method, factor(Metric, levels = c(
      "Risk-difference estimate",
      "Bias",
      "Model-based SE",
      "95% CI covers true value",
      "Rejects null"
    )))
}

design_tendencies <- function(N, adaptive_covs, outcome_delay, true_p_A, true_p_B, time_trend_B) {
  gap <- abs(true_p_A - (true_p_B + time_trend_B / 2))
  out <- character(0)

  if (N >= 200) {
    out <- c(out, "Complete randomization remains plausible when the trial is large and no strong design-stage balancing need dominates.")
  }
  if (N < 100) {
    out <- c(out, "Small or moderate sample size increases the practical value of procedures that control treatment or covariate balance.")
  }
  if ("center" %in% adaptive_covs) {
    out <- c(out, "Center is included as a balancing variable, so stratified or covariate-adaptive approaches are natural candidates.")
  }
  if (length(adaptive_covs) >= 3) {
    out <- c(out, "Several baseline covariates are being balanced; covariate-adaptive allocation becomes more attractive than full fixed stratification.")
  }
  if (outcome_delay > 0) {
    out <- c(out, "Delayed outcomes weaken the practical appeal of response-adaptive randomization because adaptation uses incomplete information.")
  }
  if (time_trend_B > 0) {
    out <- c(out, "Standard-care outcomes improve over enrollment, so temporal balance differences can translate into biased unadjusted treatment-effect estimates.")
  }
  if (gap < 0.08) {
    out <- c(out, "The assumed response-rate difference is modest; aggressive response adaptation may add complexity without much participant-benefit gain.")
  } else {
    out <- c(out, "A larger assumed response-rate difference makes the ethical motivation for response adaptation easier to see, provided outcomes are timely and reliable.")
  }

  paste(out, collapse = "\n")
}

design_tendency_items <- function(N, adaptive_covs, outcome_delay, true_p_A, true_p_B, time_trend_B) {
  strsplit(design_tendencies(N, adaptive_covs, outcome_delay, true_p_A, true_p_B, time_trend_B), "\n", fixed = TRUE)[[1]]
}

ui <- fluidPage(
  titlePanel("Randomization Design Lab"),
  sidebarLayout(
    sidebarPanel(
      checkboxGroupInput(
        "methods", "Procedures to compare:",
        choices = methods_available,
        selected = c("Complete", "Stratified complete", "Stratified permuted blocks", "Covariate-adaptive", "Response-adaptive")
      ),
      numericInput("N", "Number of participants (N):", value = 100, min = 20, max = 500, step = 10),
      numericInput("centers", "Number of centers:", value = 6, min = 1, max = 12, step = 1),
      numericInput("seed", "Random seed:", value = 431, min = 1, step = 1),
      actionButton("sim", "Simulate one trial"),
      hr(),
      selectInput(
        "strata", "Stratification variables:",
        choices = c("center", "stage", "age_group", "sex"),
        selected = "center",
        multiple = TRUE
      ),
      selectInput(
        "adaptive_covs", "Covariates used by covariate-adaptive allocation:",
        choices = c("center", "age_group", "stage", "sex"),
        selected = c("center", "age_group", "stage"),
        multiple = TRUE
      ),
      sliderInput("favor_prob", "Covariate-adaptive probability favoring better balance:", min = 0.55, max = 1, value = 0.80, step = 0.05),
      selectInput("block_size", "Within-stratum block size:", choices = c(2, 4, 6, 8), selected = 4),
      hr(),
      sliderInput("true_p_A", "True success probability, treatment A:", min = 0.05, max = 0.95, value = 0.60, step = 0.01),
      sliderInput("true_p_B", "Initial success probability, treatment B:", min = 0.05, max = 0.95, value = 0.50, step = 0.01),
      sliderInput("time_trend_B", "Treatment B (standard care) improvement over enrollment:", min = 0, max = 0.30, value = 0.05, step = 0.01),
      numericInput("burn_in", "Response-adaptive burn-in:", value = 20, min = 0, max = 200, step = 5),
      numericInput("outcome_delay", "Outcome delay in participants:", value = 0, min = 0, max = 100, step = 5),
      sliderInput("adapt_strength", "Response-adaptive updating strength:", min = 0.5, max = 10, value = 4, step = 0.5),
      hr(),
      numericInput("nsim", "Monte Carlo replicate trials:", value = 50, min = 10, max = 1000, step = 10),
      actionButton("runsim", "Run Monte Carlo")
    ),
    mainPanel(
      tabsetPanel(
        id = "tabs",
        tabPanel(
          "Walkthrough",
          tags$h4("Current setting"),
          uiOutput("design_tendencies"),
          uiOutput("method_info"),
          tags$h4("Enrollment stream"),
          tags$p(
            "The simulated participants are shared across procedures. Centers are generated with unequal recruitment probabilities, ",
            "so some centers enroll more participants than others. Age group and disease stage are then generated with center-related shifts ",
            "around the default probabilities of 45 percent older and 35 percent advanced stage. Sex is generated independently with a ",
            "50 percent male probability. This creates a setting where center balance differences can also show up as age or stage balance differences."
          ),
          tags$h4("Center profiles in the current enrollment stream"),
          DTOutput("center_profile_table"),
          hr(),
          tags$div(
            style = "max-width: 220px; margin-top: 12px;",
            numericInput("focus_id", "Participant to inspect:", value = 30, min = 1, max = 500, step = 1, width = "180px")
          ),
          tags$h4("Participant profile"),
          DTOutput("participant_profile_table"),
          tags$h4("Allocation logic"),
          DTOutput("allocation_logic_table"),
          hr(),
          tags$h4("Participant-level data"),
          checkboxInput("group_participant_table", "Group by randomization type", value = TRUE),
          DTOutput("participant_table")
        ),
        tabPanel(
          "One trial comparison",
          tags$p(
            "This tab shows one realized trial under each procedure: the allocation path, treatment allocation balance, ",
            "baseline covariate balance, and outcome consequences before averaging over repeated simulations."
          ),
          tags$h4("Allocation path"),
          fluidRow(
            column(12, tags$h4("Cumulative treatment balance"), plotOutput("timeline_plot", height = "430px"))
          ),
          fluidRow(
            column(12, tags$h4("Allocation probability over enrollment"), plotOutput("prob_plot", height = "430px"))
          ),
          tags$p(
            "When several procedures have exactly 0.50 allocation probability at the same enrollment times, ",
            "the overlapping values are slightly staggered only so all procedures remain visible."
          ),
          hr(),
          tags$h4("Treatment and covariate balance"),
          fluidRow(
            column(12, tags$h4("Treatment allocation balance"), plotOutput("count_plot", height = "380px"))
          ),
          fluidRow(
            column(12, tags$h4("Temporal treatment balance"), plotOutput("temporal_prop_plot", height = "430px"))
          ),
          fluidRow(
            column(12, tags$h4("Treatment allocation within centers"), plotOutput("center_heatmap", height = "430px"))
          ),
          fluidRow(
            column(12, tags$h4("Covariate balance by procedure"), plotOutput("covariate_smd_plot", height = "390px"))
          ),
          hr(),
          tags$h4("One-trial operating characteristics"),
          tags$p(
            "The risk-difference columns compare an unadjusted difference in observed success proportions with an adjusted linear model ",
            "that includes center, age group, disease stage, sex, and enrollment order. When standard-care outcomes improve during enrollment, ",
            "allocation balance over time can create bias in the unadjusted estimate when enrollment order differs by treatment arm."
          ),
          uiOutput("single_summary")
        ),
        tabPanel(
          "Monte Carlo",
          tags$p(
            "Repeated simulations show whether the pattern from one realized trial is typical. ",
            "Use these plots and summaries to compare balance, predictability, allocation proportions, bias, and precision."
          ),
          fluidRow(
            column(12, tags$h4("Treatment allocation balance"), plotOutput("mc_imbalance_plot", height = "520px"))
          ),
          fluidRow(
            column(12, tags$h4("Temporal treatment balance"), plotOutput("mc_temporal_plot", height = "430px"))
          ),
          fluidRow(
            column(12, tags$h4("Treatment allocation within centers"), plotOutput("mc_center_plot", height = "390px"))
          ),
          fluidRow(
            column(12, tags$h4("Covariate balance across repeated trials"), plotOutput("mc_cov_plot", height = "390px"))
          ),
          fluidRow(
            column(12, tags$h4("Predictability proxy"), plotOutput("mc_guess_plot", height = "390px"))
          ),
          fluidRow(
            column(12, tags$h4("Final allocation proportion"), plotOutput("mc_prop_plot", height = "520px"))
          ),
          hr(),
          tags$h4("Monte Carlo summary"),
          tags$p(
            "The summary table keeps only the scalar inferential operating characteristics that are not already ",
            "shown in the plots: bias, empirical SE, 95 percent confidence-interval coverage, and rejection rate ",
            "for unadjusted and adjusted analyses, shown side by side for the same metric."
          ),
          tags$p(
            "When the unadjusted and adjusted columns are similar, the randomization procedure produced little ",
            "meaningful lack of balance in enrollment time or prognostic covariates for that setting. Larger differences ",
            "suggest that covariate or temporal balance affected the unadjusted estimate, precision, coverage, or ",
            "rejection rate, so the prespecified adjusted analysis is carrying more of the inferential burden."
          ),
          uiOutput("mc_summary")
        ),
        tabPanel(
          "How to use",
          tags$div(
            style = "max-width: 900px;",
            tags$p("This capstone app compares randomization families in one shared trial setting. The default follows the tutorial's worked multicenter example: 100 sequentially enrolled participants, uneven recruitment across centers, and baseline variables whose distributions may differ by center. Because the same enrolled participants are used for each procedure, differences in balance and allocation behavior come from the randomization rule rather than from different simulated patients. The main teaching question is what information the rule uses: fixed probabilities, baseline subgroup membership, the evolving covariate distribution, or accrued outcomes."),
            tags$p("Use the sidebar to define the trial setting. Procedures to compare controls which randomization families appear throughout the app. Number of participants sets the trial size, number of centers sets how many recruiting sites generate the enrollment stream, and random seed lets you reproduce or refresh a specific simulated trial. Simulate one trial redraws the shared enrollment stream and the treatment assignments shown in Walkthrough and One trial comparison. Stratification variables define the subgroups used by the stratified complete and stratified permuted-block procedures; within-stratum block size controls how tightly the permuted-block procedure balances A and B inside each stratum."),
            tags$p("The covariate-adaptive controls define how the minimization-style procedure behaves. Covariates used by covariate-adaptive allocation select which baseline variables enter the balance score, and the probability favoring better balance sets how often the procedure chooses the treatment that would improve balance when one treatment is preferred by the score. The response-adaptive controls define the outcome-driven procedure: the success probability for treatment A is fixed, treatment B starts at its initial success probability, and Treatment B (standard care) improvement over enrollment lets B improve linearly from the first to the last participant. Burn-in keeps early assignments at 50:50 before adaptation starts, outcome delay limits which previous outcomes are available at each assignment, and updating strength controls how strongly observed success-rate differences move the allocation probability away from 0.50. Monte Carlo replicate trials sets how many repeated trials are run when the Monte Carlo tab is opened or Run Monte Carlo is clicked."),
            tags$p("Start with the Walkthrough tab to inspect the simulated enrollment stream and the assignment mechanics. It shows the current setting, center profiles for the generated participants, one selected participant's baseline profile, how each procedure would assign that participant, and the full participant-level dataset with optional grouping and download by randomization type. In the One trial comparison tab, first read the cumulative balance plot as A minus B over enrollment and the allocation-probability plot as the changing chance of treatment A. Overlapping allocation-probability values at 0.50 are offset only so all selected procedures remain visible. Then treat the balance displays as diagnostics for the same realized trial: treatment allocation balance shows final treatment counts, temporal treatment balance shows how the cumulative proportion assigned to A evolves during enrollment, the center heatmap shows the proportion assigned to A within each center, and covariate balance is summarized with maximum absolute standardized differences for each baseline variable. The one-trial operating-characteristics tables then place unadjusted and adjusted risk-difference results side by side for each procedure."),
            tags$p("Use the Monte Carlo tab after looking at a single trial. It repeats the same design many times so you can see whether a single realization is typical. The repeated-trial plots mirror the one-trial diagnostics where a long-run analogue is meaningful: treatment allocation balance summarizes final allocation balance differences, temporal treatment balance summarizes maximum balance differences during recruitment, treatment allocation within centers summarizes the largest within-center deviation from 50:50, final allocation proportion summarizes treatment allocation behavior, covariate balance summarizes maximum covariate standardized differences, and the predictability plot shows the best-guess probability implied by the allocation probabilities. Because those design diagnostics are already shown graphically, the summary tables focus on inference. They place unadjusted and adjusted results side by side for bias, empirical standard error, confidence-interval coverage, and rejection rate within each procedure. Similar values suggest that balance differences had little practical impact in the simulated setting; different values suggest that temporal or covariate balance is influencing the unadjusted analysis and that adjustment changes the operating characteristics. The purpose of the app is educational, real trials require validated systems, audit trails, access control, and a fully prespecified analysis plan.")
          )
        ),
        tabPanel(
          "Cite",
          tags$h4("Cite this software"),
          tags$p("Please cite this software in publications or presentations that use it:"),
          tags$p("Tamasi, Katalin. Randomization Design Lab, version 1.0. University Medical Center Groningen, 2026. Shiny application."),
          hr(),
