        )
      )
    )
  )
)

server <- function(input, output, session) {
  params <- reactive({
    list(
      p_A = 0.5,
      strata_vars = parse_covariates(input$strata),
      adaptive_covs = parse_covariates(input$adaptive_covs),
      favor_prob = input$favor_prob,
      block_size = as.numeric(input$block_size),
      true_p_A = input$true_p_A,
      true_p_B = input$true_p_B,
      time_trend_B = input$time_trend_B,
      burn_in = min(input$burn_in, input$N),
      outcome_delay = input$outcome_delay,
      adapt_strength = input$adapt_strength
    )
  })

  enrollment <- eventReactive(input$sim, {
    generate_enrollment(input$N, input$centers, input$seed)
  }, ignoreNULL = FALSE)

  single_trial <- eventReactive(input$sim, {
    simulate_one_trial(
      enrollment(),
      parse_method_selection(input$methods),
      params(),
      input$seed + 5000
    )
  }, ignoreNULL = FALSE)

  observeEvent(input$N, {
    updateNumericInput(session, "focus_id", max = input$N, value = min(input$focus_id, input$N))
  })

  output$method_info <- renderUI({
    selected <- parse_method_selection(input$methods)
    info <- method_info %>% filter(method %in% selected)
    tags$table(
      class = "table table-condensed table-striped",
      style = "width: 100%; table-layout: fixed; margin-top: 12px;",
      tags$thead(
        tags$tr(
          tags$th(style = "width: 22%;", "Procedure"),
          tags$th(style = "width: 28%;", "Information used"),
          tags$th(style = "width: 25%;", "Main gain"),
          tags$th(style = "width: 25%;", "Main cost")
        )
      ),
      tags$tbody(
        lapply(seq_len(nrow(info)), function(i) {
          tags$tr(
            tags$td(tags$strong(info$method[i])),
            tags$td(info$uses[i]),
            tags$td(info$main_gain[i]),
            tags$td(info$main_cost[i])
          )
        })
      )
    )
  })

  focused_rows <- reactive({
    dat <- single_trial()
    focus <- min(max(input$focus_id, 1), input$N)
    dat %>% filter(id == focus) %>% left_join(method_info, by = "method")
  })

  output$participant_profile_table <- renderDT({
    profile <- focused_rows() %>%
      slice(1) %>%
      transmute(
        Participant = id,
        Center = as.character(center),
        Age = as.character(age_group),
        Stage = as.character(stage),
        Sex = as.character(sex)
      )

    datatable(profile, rownames = FALSE, options = list(dom = "t"))
  })

  output$allocation_logic_table <- renderDT({
    logic <- focused_rows() %>%
      transmute(
        Method = method,
        `Score if A` = score_A,
        `Score if B` = score_B,
        `Observed A outcomes` = observed_A,
        `Observed B outcomes` = observed_B,
        `Pr(A)` = prob_A,
        Assignment = as.character(treatment)
      )

    datatable(logic, rownames = FALSE, options = list(dom = "t", scrollX = TRUE)) %>%
      formatRound(columns = c("Score if A", "Score if B", "Pr(A)"), digits = 2)
  })

  output$timeline_plot <- renderPlot({
    dat <- single_trial() %>%
      mutate(
        method_offset = (as.integer(factor(method, levels = methods_available)) - 3) * 0.16,
        imbalance_staggered = imbalance + method_offset
      )
    ggplot(dat, aes(id, imbalance_staggered, color = method)) +
      geom_hline(yintercept = 0, color = "gray70") +
      geom_step(linewidth = 0.9) +
      labs(
        x = "Enrollment order",
        y = "Cumulative balance difference (A - B)",
        color = "Procedure"
      ) +
      theme_minimal(base_size = 13)
  })

  output$prob_plot <- renderPlot({
    dat <- single_trial() %>%
      mutate(
        method_offset = (as.integer(factor(method, levels = methods_available)) - 3) * 0.012,
        prob_A_staggered = ifelse(
          abs(prob_A - 0.5) < 1e-12,
          prob_A + method_offset,
          prob_A
        )
      )
    ggplot(dat, aes(id, prob_A_staggered, color = method)) +
      geom_hline(yintercept = 0.5, color = "gray70", linetype = "dashed") +
      geom_step(linewidth = 0.9, alpha = 0.9) +
      ylim(0, 1) +
      labs(
        x = "Enrollment order",
        y = "Allocation probability for A",
        color = "Procedure"
      ) +
      theme_minimal(base_size = 13)
  })

  output$count_plot <- renderPlot({
    dat <- single_trial() %>% count(method, treatment)
    ggplot(dat, aes(treatment, n, fill = treatment)) +
      geom_col(show.legend = FALSE) +
      facet_wrap(~method) +
      labs(x = "Treatment", y = "Participants") +
      theme_minimal(base_size = 13)
  })

  output$temporal_prop_plot <- renderPlot({
    dat <- single_trial()
    ggplot(dat, aes(id, cum_prop_A, color = method)) +
      geom_hline(yintercept = 0.5, color = "gray60", linetype = "dashed") +
      geom_step(linewidth = 0.9, alpha = 0.9) +
      ylim(0, 1) +
      labs(
        x = "Enrollment order",
        y = "Cumulative proportion assigned to A",
        color = "Procedure"
      ) +
      theme_minimal(base_size = 13)
  })

  output$covariate_smd_plot <- renderPlot({
    dat <- covariate_balance_long(single_trial())
    method_levels <- methods_available[methods_available %in% as.character(unique(dat$method))]

    ggplot(dat, aes(max_abs_smd, method, color = covariate)) +
      geom_vline(xintercept = 0.10, color = "gray70", linetype = "dotted") +
      geom_vline(xintercept = 0.25, color = "gray65", linetype = "dashed") +
      geom_point(size = 3.4, alpha = 0.9, position = position_dodge(width = 0.45)) +
      scale_y_discrete(limits = rev(method_levels)) +
      labs(
        x = "Maximum absolute standardized difference",
        y = "Procedure",
        color = "Covariate"
      ) +
      theme_minimal(base_size = 13) +
      theme(legend.position = "bottom")
  })

  output$single_summary <- renderUI({
    sumdat <- trial_metrics(single_trial(), params()$true_p_A, params()$true_p_B, params()$time_trend_B) %>%
      format_single_trial_summary()
    methods <- methods_available[methods_available %in% as.character(unique(sumdat$method))]

    tags$div(
      lapply(methods, function(m) {
        table_id <- paste0("single_summary_", match(m, methods_available))
        method_dat <- sumdat %>%
          filter(method == m) %>%
          select(Metric, Unadjusted, Adjusted)

        output[[table_id]] <- renderDT({
          datatable(method_dat, rownames = FALSE, options = list(dom = "t", paging = FALSE)) %>%
            formatRound(columns = c("Unadjusted", "Adjusted"), digits = 2)
        })

        tags$div(
          style = "margin-bottom: 22px;",
          tags$h4(m),
          DTOutput(table_id)
        )
      })
    )
  })

  output$center_heatmap <- renderPlot({
    dat <- single_trial() %>%
      count(method, center, treatment) %>%
      complete(method, center, treatment = factor(c("A", "B"), levels = c("A", "B")), fill = list(n = 0)) %>%
      group_by(method, center) %>%
      mutate(prop = n / sum(n)) %>%
      ungroup() %>%
      filter(treatment == "A")
    method_levels <- methods_available[methods_available %in% as.character(unique(dat$method))]

    ggplot(dat, aes(center, method, fill = prop)) +
      geom_tile(color = "white") +
      scale_fill_gradient2(low = "#b2182b", mid = "white", high = "#2166ac", midpoint = 0.5, limits = c(0, 1)) +
      scale_y_discrete(limits = rev(method_levels)) +
      labs(x = "Center", y = "Procedure", fill = "Prop A") +
      theme_minimal(base_size = 12) +
      theme(axis.text.x = element_text(angle = 45, hjust = 1))
  })

  output$center_profile_table <- renderDT({
    dat <- enrollment() %>%
      group_by(center) %>%
      summarise(
        Participants = n(),
        `Percent older` = mean(age_group == "Older") * 100,
        `Percent advanced stage` = mean(stage == "Advanced") * 100,
        `Percent male` = mean(sex == "Male") * 100,
        .groups = "drop"
      )

    datatable(dat, rownames = FALSE, options = list(dom = "t", pageLength = 12)) %>%
      formatRound(columns = c("Percent older", "Percent advanced stage", "Percent male"), digits = 1)
  })

  output$participant_table <- renderDT({
    dat <- single_trial() %>%
      select(method, id, center, age_group, stage, sex, treatment, prob_A, score_A, score_B, true_prob_A_i, true_prob_B_i, outcome)
    table_options <- list(
      dom = "Bfrtip",
      buttons = c("csv", "excel"),
      pageLength = 15,
      scrollX = TRUE
    )
    table_extensions <- "Buttons"
    if (isTRUE(input$group_participant_table)) {
      table_options$rowGroup <- list(dataSrc = 0)
      table_extensions <- c("Buttons", "RowGroup")
    }

    datatable(dat, rownames = FALSE, extensions = table_extensions, options = table_options) %>%
      formatRound(columns = c("prob_A", "score_A", "score_B", "true_prob_A_i", "true_prob_B_i"), digits = 2)
  })

  mc_trigger <- reactiveVal(0)
  observeEvent(input$runsim, {
    mc_trigger(mc_trigger() + 1)
  })
  observeEvent(input$tabs, {
    if (identical(input$tabs, "Monte Carlo")) mc_trigger(mc_trigger() + 1)
  }, ignoreInit = TRUE)

  mc_results <- eventReactive(mc_trigger(), {
    req(mc_trigger() > 0)
    withProgress(message = "Running Monte Carlo simulations", value = 0, {
      incProgress(0.2)
      res <- run_monte_carlo(
        input$N,
        input$centers,
        parse_method_selection(input$methods),
        params(),
        input$seed + 20000,
        input$nsim
      )
      incProgress(1)
      res
    })
  })

  output$mc_imbalance_plot <- renderPlot({
    req(mc_results())
    ggplot(mc_results(), aes(final_imbalance, fill = method)) +
      geom_histogram(alpha = 0.78, bins = 18, color = "white") +
      facet_wrap(~method, ncol = 2) +
      labs(x = "Final absolute treatment allocation balance difference |NA - NB|", y = "Replicate trials") +
      theme_minimal(base_size = 13) +
      theme(legend.position = "none")
  })

  output$mc_temporal_plot <- renderPlot({
    req(mc_results())
    dat <- mc_results()
    method_levels <- methods_available[methods_available %in% as.character(unique(dat$method))]
    ggplot(dat, aes(method, max_temporal_imbalance, fill = method)) +
      geom_boxplot(show.legend = FALSE) +
      scale_x_discrete(limits = rev(method_levels)) +
      coord_flip() +
      labs(x = NULL, y = "Maximum absolute balance difference during enrollment") +
      theme_minimal(base_size = 13)
  })

  output$mc_center_plot <- renderPlot({
    req(mc_results())
    dat <- mc_results()
    method_levels <- methods_available[methods_available %in% as.character(unique(dat$method))]
    ggplot(dat, aes(method, max_center_allocation_deviation, fill = method)) +
      geom_boxplot(show.legend = FALSE) +
      scale_x_discrete(limits = rev(method_levels)) +
      coord_flip() +
      labs(x = NULL, y = "Largest within-center deviation from 50:50") +
      theme_minimal(base_size = 13)
  })

  output$mc_cov_plot <- renderPlot({
    req(mc_results())
    dat <- mc_results()
    method_levels <- methods_available[methods_available %in% as.character(unique(dat$method))]
    ggplot(dat, aes(method, max_covariate_smd, fill = method)) +
      geom_boxplot(show.legend = FALSE) +
      scale_x_discrete(limits = rev(method_levels)) +
      coord_flip() +
      labs(x = NULL, y = "Maximum covariate standardized difference") +
      theme_minimal(base_size = 13)
  })

  output$mc_guess_plot <- renderPlot({
    req(mc_results())
    dat <- mc_results()
    method_levels <- methods_available[methods_available %in% as.character(unique(dat$method))]
    ggplot(dat, aes(method, mean_guess_probability, fill = method)) +
      geom_boxplot(show.legend = FALSE) +
      scale_x_discrete(limits = rev(method_levels)) +
      coord_flip() +
      ylim(0.5, 1) +
      geom_hline(yintercept = 0.5, color = "gray65", linetype = "dashed") +
      labs(x = NULL, y = "Mean best-guess probability") +
      theme_minimal(base_size = 13)
  })

  output$mc_prop_plot <- renderPlot({
    req(mc_results())
    ggplot(mc_results(), aes(proportion_A, fill = method)) +
      geom_histogram(alpha = 0.78, bins = 18, color = "white") +
      facet_wrap(~method, ncol = 2) +
      geom_vline(xintercept = 0.5, linetype = "dashed", color = "gray30") +
      labs(x = "Final proportion assigned to A", y = "Replicate trials") +
      theme_minimal(base_size = 13) +
      theme(legend.position = "none")
  })

  output$mc_summary <- renderUI({
    req(mc_results())
    sumdat <- format_metric_summary(mc_results())
    methods <- methods_available[methods_available %in% as.character(unique(sumdat$method))]

    tags$div(
      lapply(methods, function(m) {
        table_id <- paste0("mc_summary_", match(m, methods_available))
        method_dat <- sumdat %>%
          filter(method == m) %>%
          select(Metric, Unadjusted, Adjusted)

        output[[table_id]] <- renderDT({
          datatable(method_dat, rownames = FALSE, options = list(dom = "t", paging = FALSE)) %>%
            formatRound(columns = c("Unadjusted", "Adjusted"), digits = 2)
        })

        tags$div(
          style = "margin-bottom: 22px;",
          tags$h4(m),
          DTOutput(table_id)
        )
      })
    )
  })

  output$design_tendencies <- renderUI({
    items <- design_tendency_items(
      input$N,
      parse_covariates(input$adaptive_covs),
      input$outcome_delay,
      input$true_p_A,
      input$true_p_B,
      input$time_trend_B
    )
    tags$div(
      style = "line-height: 1.45;",
      tags$p(
        "Based on the current controls, the app highlights these design considerations:"
      ),
      tags$ul(lapply(items, tags$li))
    )
  })

}

shinyApp(ui, server)
